import React from 'react';

const Education = () => {
  const education = [
    { institution: 'University A', degree: 'Bachelor of Science', year: '2018 - 2022' },
    { institution: 'School B', degree: 'High School', year: '2016 - 2018' },
  ];

  return (
    <section id="education" className="education">
      <h2>Education</h2>
      <div class="block-separator">
            <h4 class="block-title">Bachelor of Engineering (CSE)</h4>
            <h5 class="block-subtitle">Government College of Engineering, Erode</h5>
            <p class="block-content">Affiliated to Anna University, completed in 2018.</p>
        </div>

        <div class="block-separator">
            <h4 class="block-title">Diploma (CS)</h4>
            <h5 class="block-subtitle">Valivalam Desikar Polytechnic College, Nagapattinam</h5>
            <p class="block-content">Completed in 2015.</p>
        </div>

        <div class="block-separator">
            <h4 class="block-title">10th Grade</h4>
            <h5 class="block-subtitle">Government Higher Secondary School, Peralam</h5>
            <p class="block-content">Completed in 2012.</p>
        </div>
    </section>
  );
};

export default Education;
